  const audioRef = useRef<HTMLAudioElement | null>(null);
  const canvasRef = useRef<HTMLCanvasElement | null>(null);
  const scriptContainerRef = useRef<HTMLDivElement | null>(null);
  const segmentRefs = useRef<(HTMLDivElement | null)[]>([]);
  const animationRef = useRef<number | null>(null);
  const abortRef = useRef<boolean>(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);

  const hosts = HOST_CONFIG[selectedTone] || HOST_CONFIG['Engaging'];

  useEffect(() => {
    if (!script) {
      setSegments([]);
      return;
    }
    const lines = script.split('\n').filter(line => line.trim().length > 0);

    const parsed: ScriptSegment[] = [];
    let accumulatedChars = 0;

    const validLines = lines.map(line => {
      const splitIdx = line.indexOf(':');
      if (splitIdx === -1) return null;

      const speaker = line.substring(0, splitIdx).trim();
      const text = line.substring(splitIdx + 1).trim();

      return { speaker, text };
    }).filter(l => l !== null) as { speaker: string, text: string }[];

    const totalChars = validLines.reduce((acc, l) => acc + l.text.length, 0);

    validLines.forEach(l => {
      const startPct = accumulatedChars / (totalChars || 1);
      accumulatedChars += l.text.length;
      const endPct = accumulatedChars / (totalChars || 1);
      parsed.push({ speaker: l.speaker, text: l.text, startPct, endPct });
    });

    setSegments(parsed);
  }, [script, hosts]);

  const pcmToWavBlobUrl = (base64: string) => {
    const binaryString = window.atob(base64);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, o: number, s: string) => { for (let i = 0; i < s.length; i++) v.setUint8(o + i, s.charCodeAt(i)); };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return URL.createObjectURL(new Blob([buffer], { type: 'audio/wav' }));
  };

  const handleToggleGeneration = async () => {
    if (isLoading) {
      abortRef.current = true;
      setIsLoading(false);
      setHasInitiated(true); 
      return;
    }

    setIsLoading(true);
    setHasInitiated(true);
    setError(null);
    abortRef.current = false;

    try {
      const result = await generatePodcastAudio(fileContext, chapter, selectedTone, hosts, selectedLanguage);

      if (abortRef.current) return;

      setAudioSrc(pcmToWavBlobUrl(result.audio));
      setScript(result.script);
      setActiveIndex(-1);
    } catch (e: any) {
      if (!abortRef.current) {
        setError(e.message || "Failed to generate podcast.");
      }
    } finally {
      if (!abortRef.current) {
        setIsLoading(false);
      }
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      if (!audioContextRef.current) initAudioVisualizer();
      if (audioContextRef.current?.state === 'suspended') audioContextRef.current.resume();
      audioRef.current.play();
    }
    setIsPlaying(!isPlaying);
  };

  const initAudioVisualizer = () => {
    if (!audioRef.current || audioContextRef.current) return;
    try {
      const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
      const ctx = new AudioContext();
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 128;
      const source = ctx.createMediaElementSource(audioRef.current);
      source.connect(analyser);
      analyser.connect(ctx.destination);
      audioContextRef.current = ctx;
      analyserRef.current = analyser;
    } catch (e) { console.warn("Visualizer failed", e); }
  };

  const handleTimeUpdate = () => {
    if (!audioRef.current) return;
    const { currentTime, duration } = audioRef.current;
    if (!duration) return;
    const currentPct = currentTime / duration;
    const index = segments.findIndex(s => currentPct >= s.startPct && currentPct < s.endPct);
    if (index !== -1 && index !== activeIndex) {
      setActiveIndex(index);
      segmentRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  };

  useEffect(() => {
    if (audioRef.current) {
      audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate]);

  useEffect(() => {
    if (!isPlaying || !canvasRef.current) {
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      return;
    }
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const draw = () => {
      const bufferLength = analyserRef.current?.frequencyBinCount || 0;
      const dataArray = new Uint8Array(bufferLength);
      if (analyserRef.current) analyserRef.current.getByteFrequencyData(dataArray);
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const centerX = canvas.width / 2;
      const bars = bufferLength / 2;
      const step = canvas.width / 2 / bars;
      for (let i = 0; i < bars; i++) {
        const value = dataArray[i];
        const h = (value / 255) * canvas.height * 0.9;
        ctx.fillStyle = `rgb(${value}, ${243 - value}, 255)`;
        ctx.fillRect(centerX + (i * step), (canvas.height - h) / 2, step - 2, h);
        ctx.fillRect(centerX - ((i + 1) * step), (canvas.height - h) / 2, step - 2, h);
      }
      animationRef.current = requestAnimationFrame(draw);
    };
    draw();
    return () => { if (animationRef.current) cancelAnimationFrame(animationRef.current); };
  }, [isPlaying]);

  const renderButtonLabel = () => {
    if (isLoading) return "STOP";
    if (hasInitiated) return "REGENERATE";
    return "INITIATE";
  };

  const renderButtonIcon = () => {
    if (isLoading) return <Square size={14} fill="currentColor" />;
    if (hasInitiated) return <RefreshCw size={14} />;
    return <Play size={14} fill="currentColor" />;
  };

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 items-center overflow-hidden">
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full max-w-[2300px] flex-wrap gap-2">
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono">
                 <Mic2 size={18} className="text-[#00f3ff]" />
                 <span>Neural_Podcast</span>
              </div>
              <div className="hidden md:flex items-center gap-3 text-[10px] font-mono border-l border-zinc-800 pl-4 uppercase">
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">HOST:</span>
                    <span className="text-cyan-400 font-bold">{hosts.host1.toUpperCase()}</span>
                 </div>
                 <div className="text-zinc-700">|</div>
                 <div className="flex items-center gap-1">
                    <span className="text-zinc-600">CO-HOST:</span>
                    <span className="text-[#ff003c] font-bold">{hosts.host2.toUpperCase()}</span>
                 </div>
              </div>
          </div>
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2 bg-black/50 p-1 rounded-sm border border-zinc-800">
                 <div className="p-1.5 text-zinc-500"><Settings2 size={16} /></div>
                 <select value={selectedTone} onChange={(e) => setSelectedTone(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-24 bg-[#050505]">{TONES.map(t => <option key={t} value={t}>{t}</option>)}</select>
                 <div className="w-[1px] h-4 bg-zinc-700"></div>
                 <div className="p-1.5 text-zinc-500"><Globe size={16} /></div>
                 <select value={selectedLanguage} onChange={(e) => setSelectedLanguage(e.target.value)} className="bg-transparent text-xs text-[#00f3ff] outline-none cursor-pointer font-mono uppercase w-24 bg-[#050505]">{LANGUAGES.map(lang => <option key={lang} value={lang}>{lang}</option>)}</select>
              </div>
              <button 
                onClick={handleToggleGeneration} 
                className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[120px] justify-center ${isLoading ? 'bg-[#ff003c] text-white hover:bg-rose-600' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'}`}
              >
                 {renderButtonIcon()}
                 {renderButtonLabel()}
              </button>
          </div>
       </div>

       <div className="flex-1 flex flex-col gap-4 overflow-hidden w-full max-w-[2300px]">
           <div className="bg-[#0a0a0c] border border-zinc-800 rounded-lg p-0 relative overflow-hidden shrink-0 h-[277px] flex flex-col">
               <div className="flex-1 bg-[#050505] w-full flex items-center justify-center overflow-hidden relative group border-b border-zinc-900">
                  <div className="absolute inset-0 bg-[linear-gradient(rgba(0,255,255,0.05)_1px,transparent_1px),linear-gradient(90deg,rgba(0,255,255,0.05)_1px,transparent_1px)] bg-[size:20px_20px] pointer-events-none"></div>

                  {/* Centered Episode Title Overlay */}
                  <div className="absolute inset-0 flex items-center justify-center z-10 pointer-events-none">
                      <div className="bg-black/60 backdrop-blur-md border border-zinc-800/50 px-6 py-2 rounded-sm shadow-[0_0_30px_rgba(0,0,0,0.8)] border-cyan-500/20">
                         <span className="text-xs font-bold text-cyan-400 font-tech uppercase tracking-[0.3em] opacity-90 whitespace-nowrap drop-shadow-[0_0_8px_rgba(0,243,255,0.5)]">EPISODE: {chapter.title.toUpperCase()}</span>
                      </div>
                  </div>

                  {isLoading ? (
                    <div className="z-20 scale-75 animate-fade-in">
                      <Loader text="SYNTHESIZING_COMM_LINK..." />
                    </div>
                  ) : audioSrc ? (
                    <canvas ref={canvasRef} width={1800} height={192} className="w-full h-full opacity-90" />
                  ) : (
                    <div className="flex flex-col items-center gap-2 text-zinc-700 font-mono text-xs">
                      <Activity size={32} className="opacity-20" />
                      <span>AWAITING_STREAM</span>
                    </div>
                  )}
               </div>
               <div className="bg-[#020202] p-3 flex items-center justify-between">
                   <div className="flex-1 flex items-center gap-4 text-[10px] font-mono uppercase">
                        {SPEEDS.map(s => (
                          <button 
                            key={s} 
                            onClick={() => setPlaybackRate(s)} 
                            className={`transition-colors font-mono ${playbackRate === s ? 'text-[#00f3ff] font-bold underline underline-offset-4' : 'text-zinc-600 hover:text-zinc-400'}`}
                          >
                            {s.toFixed(1)}x
                          </button>
                        ))}
                   </div>
                   <div className="flex-2 flex items-center justify-center gap-6">
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime -= 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCcw size={20} /></button>
                       <button onClick={togglePlay} disabled={!audioSrc} className={`w-10 h-10 rounded-full transition-all flex items-center justify-center border-2 ${isPlaying ? 'bg-transparent border-[#00f3ff] text-[#00f3ff] shadow-[0_0_15px_rgba(0,243,255,0.3)]' : 'bg-[#00f3ff] border-[#00f3ff] text-black shadow-[0_0_20px_rgba(0,243,255,0.6)] hover:scale-105'}`}>{isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" className="ml-1" />}</button>
                       <button onClick={() => { if(audioRef.current) audioRef.current.currentTime += 15; }} disabled={!audioSrc} className="p-2 text-zinc-500 hover:text-cyan-400 transition-colors hover:bg-zinc-900 rounded-full disabled:opacity-30"><RotateCw size={20} /></button>
                   </div>
                   <div className="flex-1 flex justify-end">
                       <a href={audioSrc || '#'} download={`podcast-${chapter.id}.wav`} className={`p-2 text-zinc-600 transition-colors rounded-full ${audioSrc ? 'hover:text-[#ff003c] hover:bg-zinc-900' : 'opacity-30'}`} onClick={(e) => !audioSrc && e.preventDefault()}><Download size={20} /></a>
                   </div>
               </div>
           </div>

           <audio ref={audioRef} src={audioSrc || undefined} onTimeUpdate={handleTimeUpdate} onEnded={() => setIsPlaying(false)} className="hidden" />

           {segments.length > 0 ? (
               <div className="h-[277px] min-h-0 bg-transparent overflow-hidden flex flex-col">
                  <div ref={scriptContainerRef} className="flex-1 overflow-y-auto p-6 space-y-8 scroll-smooth custom-scrollbar font-mono text-sm">
                    {segments.map((seg, idx) => {
                      const isActive = idx === activeIndex;
                      const h1 = hosts.host1.toUpperCase();
                      const h2 = hosts.host2.toUpperCase();
                      const cur = seg.speaker.toUpperCase();

                      const isHost1 = cur === h1 || cur.includes(h1);
                      const isHost2 = cur === h2 || cur.includes(h2);

                      const leftAligned = isHost1 || (!isHost2 && idx % 2 === 0);

                      return (
                        <div key={idx} ref={el => { segmentRefs.current[idx] = el; }} className={`flex w-full ${leftAligned ? 'justify-start' : 'justify-end'} animate-fade-in`}>
                            <div className={`relative max-w-[90%] rounded-sm p-4 pt-5 border transition-all duration-300 ${isActive ? (leftAligned ? 'bg-cyan-950/20 border-cyan-500/50 shadow-[0_0_15px_rgba(6,182,212,0.1)]' : 'bg-rose-950/20 border-[#ff003c]/50 shadow-[0_0_15px_rgba(255,0,60,0.1)]') : 'bg-zinc-900/30 border-zinc-800 hover:border-zinc-700'}`}>
                                <div className={`absolute -top-2.5 px-2 py-0.5 text-[9px] font-bold uppercase tracking-wider border ${leftAligned ? 'left-4 bg-cyan-900 border-cyan-500/50 text-cyan-200' : 'right-4 bg-rose-900 border-[#ff003c]/50 text-rose-200'}`}>
                                    {seg.speaker}
                                </div>
                                <p className={`leading-relaxed ${isActive ? 'text-white' : 'text-zinc-400'}`}>{seg.text}</p>
                                {isActive && <div className={`absolute -left-1 top-1/2 -translate-y-1/2 w-0.5 h-1/2 ${leftAligned ? 'bg-cyan-500' : 'bg-[#ff003c]'}`}></div>}
                            </div>
                        </div>
                      );
                    })}
                  </div>
               </div>
           ) : !isLoading && !error && (
               <div className="h-[277px] bg-black/40 border border-dashed border-zinc-800 rounded-lg flex flex-col items-center justify-center text-zinc-600 gap-4 font-mono">
                   <Radio size={48} className="opacity-20 animate-pulse" />
                   <div className="text-center space-y-1">
                      <p className="text-xs uppercase tracking-[0.3em]">Ready_to_Stream</p>
                      <p className="text-[10px] opacity-50">Select tone and language above to begin decoding</p>
                   </div>
               </div>
           )}

           {error && (
               <div className="h-[277px] bg-rose-950/10 border border-rose-900/30 rounded-lg flex flex-col items-center justify-center text-rose-500 p-8 text-center font-mono">
                   <AlertCircle size={32} className="mb-4" />
                   <p className="text-xs font-bold uppercase mb-2">Signal_Lost</p>
                   <p className="text-[10px] max-w-sm mb-6">{error}</p>
                   <button onClick={handleToggleGeneration} className="px-6 py-2 bg-rose-600 hover:bg-rose-500 text-white rounded-sm text-xs font-bold transition-all uppercase tracking-widest">Retry_Connection</button>
               </div>
           )}
       </div>
    </div>
  );
};

import { GoogleGenAI, Type, Modality, Chat, Content } from "@google/genai";
import { BookStructure, Chapter, Concept, DictionaryEntry, FileContext } from "../types";

const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

export const cleanGenAiText = (text: string): string => {
  if (!text) return "";
  return text
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`/g, '')
    .replace(/^#+\s/gm, '') 
    .trim();
};

const withRetry = async <T>(fn: () => Promise<T>, retries = 5, delay = 3000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const getErrorDetails = (e: any) => {
        if (e.error && typeof e.error === 'object') return e.error;
        if (e.response?.data?.error) return e.response.data.error;
        return e;
    };
    const details = getErrorDetails(error);
    const code = details.code || details.status || error.status || error.code;
    const message = String(details.message || error.message || JSON.stringify(error)).toLowerCase();
    const status = String(details.status || "").toLowerCase();

    const isNetworkError = message.includes('xhr') || message.includes('fetch') || message.includes('network');
    const numericCode = Number(code);
    const isServerError = (numericCode >= 500 && numericCode < 600);
    const isRateLimit = numericCode === 429 || message.includes('429') || message.includes('quota') || status.includes('resource_exhausted');

    if (retries > 0 && (isNetworkError || isServerError || isRateLimit)) {
      let nextDelay = isRateLimit ? Math.max(delay, 15000) * 1.5 : delay * 2;
      nextDelay = Math.min(nextDelay, 180000) + (Math.random() * 2000); 
      console.warn(`Gemini API request failed (${code}). Retrying in ${Math.round(nextDelay/1000)}s...`);
      await new Promise(resolve => setTimeout(resolve, nextDelay));
      return withRetry(fn, retries - 1, nextDelay);
    }
    if (typeof error === 'object' && !error.message && details.message) throw new Error(details.message);
    throw error;
  }
};

const getFilePart = (file: FileContext) => {
  if (file.isText) return { text: file.content };
  return { inlineData: { mimeType: file.mimeType, data: file.content } };
};

export const analyzeBookStructure = async (file: FileContext): Promise<BookStructure> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: "Analyze this book content. Extract the book title, author, and a list of chapters. For each chapter, provide a title and a one-sentence description. If the content is short, divide it into logical sections. Provide a UNIQUE list of chapters. Return strictly JSON." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["id", "title"]
              }
            }
          },
          required: ["title", "author", "chapters"]
        }
      }
    });
    if (!response.text) throw new Error("Failed to analyze book structure");
    const data = JSON.parse(response.text);
    return { ...data, id: crypto.randomUUID(), bookmarks: [] } as BookStructure;
  }, 5, 8000);
};

interface HostConfig {
  host1: string;
  voice1: string;
  host2: string;
  voice2: string;
}

export const generatePodcastAudio = async (
  file: FileContext,
  chapter: Chapter,
  tone: string = 'Engaging',
  hosts: HostConfig,
  language: string = 'English'
): Promise<{ audio: string; script: string; episodeTitle: string }> => {
  return withRetry(async () => {
    const ai = getAi();
    const scriptResponse = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Create a ${tone} podcast conversation discussing the content of "${chapter.title}". 

          Speakers: ${hosts.host1} (Main Host) and ${hosts.host2} (Co-Host).

          CRITICAL INSTRUCTIONS:
          1. START the script IMMEDIATELY with the first host speaking.
          2. DO NOT include music cues or bracketed actions.
          3. EVERY LINE must follow the format: "SpeakerName: Dialogue".
          4. NO extra labels, brackets, or formatting outside of "SpeakerName: Dialogue".
          5. Use exactly these speaker names: "${hosts.host1}" and "${hosts.host2}".
          6. Ensure the dialogue feels natural and conversational.
          7. Language: ${language}.
          8. Length: Approx 2 minutes.
          9. Also provide a catchy, short summary title for this specific episode (max 6 words).` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            episodeTitle: { type: Type.STRING },
            script: { type: Type.STRING }
          },
          required: ["episodeTitle", "script"]
        }
      }
    });

    const parsedResponse = JSON.parse(scriptResponse.text || "{}");
    const script = parsedResponse.script;
    const episodeTitle = parsedResponse.episodeTitle;

    if (!script) throw new Error("Failed to generate script");

    const audioResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: script }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              { speaker: hosts.host1, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice1 } } },
              { speaker: hosts.host2, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice2 } } }
            ]
          }
        }
      }
    });
    const base64Audio = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Failed to generate audio content");
    return { audio: base64Audio, script, episodeTitle };
  }, 6, 8000);
};

export const extractConcepts = async (file: FileContext, chapter: Chapter): Promise<Concept[]> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Identify 3-5 complex or new concepts from "${chapter.title}". For each, provide a definition (source language) and a vivid visual description (English). Return JSON.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              term: { type: Type.STRING },
              definition: { type: Type.STRING },
              visualPrompt: { type: Type.STRING }
            }
          }
        }
      }
    });
    return JSON.parse(response.text || "[]") as Concept[];
  }, 4, 5000);
};

export const generateConceptImage = async (visualPrompt: string, style: string = 'Digital Art', aspectRatio: string = '1:1'): Promise<string> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-image",
      contents: { parts: [{ text: `${style} style. ${visualPrompt}` }] },
      config: { imageConfig: { aspectRatio: aspectRatio as any } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("No image generated");
  }, 3, 5000);
};

export const extractDictionary = async (file: FileContext, chapter: Chapter): Promise<DictionaryEntry[]> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Identify 5-7 specialized words in "${chapter.title}". Return JSON with word, context, definition.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              word: { type: Type.STRING },
              context: { type: Type.STRING },
              definition: { type: Type.STRING }
            }
          }
        }
      }
    });
    return JSON.parse(response.text || "[]") as DictionaryEntry[];
  }, 4, 4000);
};

